diff --git a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
index 439a86d951a8..fc49125e5d15 100644
--- a/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstructionCombining.cpp
@@ -1706,6 +1706,7 @@ static Value *foldOperationIntoSelectOperand(Instruction &I, SelectInst *SI,
   return Clone;
 }

+
 Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
                                                 bool FoldWithMultiUse) {
   // Don't modify shared select instructions unless set FoldWithMultiUse
@@ -1719,6 +1720,53 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   if (SI->getType()->isIntOrIntVectorTy(1))
     return nullptr;

+  // Fold through a NaN-masking floating-point select:
+  //   %c = fcmp ord X, K0
+  //   %s = select i1 %c, X, K0
+  //   %r = fcmp oeq/ueq %s, K1
+  //
+  // If the false arm comparison:
+  //   fcmp oeq/ueq K0, K1
+  // folds to false, then the whole expression is equivalent to:
+  //   fcmp oeq/ueq X, K1
+  //
+  // On the true arm, %c proves X is ordered, so using X directly is safe.
+  // On the false arm, the select yields K0, and that arm is known false.
+  if (auto *FCmp = dyn_cast<FCmpInst>(&Op)) {
+    if (FCmp->isEquality()) {
+      if (auto *Cond = dyn_cast<FCmpInst>(SI->getCondition())) {
+        if (Cond->getPredicate() == FCmpInst::FCMP_ORD) {
+          Value *X = Cond->getOperand(0);
+          Value *K0 = Cond->getOperand(1);
+
+          if (TV == X && FV == K0) {
+            Value *CmpOp0 = FCmp->getOperand(0);
+            Value *CmpOp1 = FCmp->getOperand(1);
+            Value *OtherOp = nullptr;
+
+            if (CmpOp0 == SI)
+              OtherOp = CmpOp1;
+            else if (CmpOp1 == SI)
+              OtherOp = CmpOp0;
+
+            if (OtherOp) {
+              if (auto *CFV = dyn_cast<Constant>(FV)) {
+                if (auto *COther = dyn_cast<Constant>(OtherOp)) {
+                  if (Constant *FoldedFalseArm = ConstantFoldCompareInstOperands(
+                          FCmp->getPredicate(), CFV, COther, DL, &TLI);
+                      match(FoldedFalseArm, m_Zero())) {
+                    return FCmpInst::Create(Instruction::FCmp,
+                                            FCmp->getPredicate(), X, OtherOp);
+                  }
+                }
+              }
+            }
+          }
+        }
+      }
+    }
+  }
+
   // Test if a FCmpInst instruction is used exclusively by a select as
   // part of a minimum or maximum operation. If so, refrain from doing
   // any other folding. This helps out other analyses which understand
@@ -1749,6 +1797,7 @@ Instruction *InstCombinerImpl::FoldOpIntoSelect(Instruction &Op, SelectInst *SI,
   return SelectInst::Create(SI->getCondition(), NewTV, NewFV, "", nullptr, SI);
 }

+
 static Value *simplifyInstructionWithPHI(Instruction &I, PHINode *PN,
                                          Value *InValue, BasicBlock *InBB,
                                          const DataLayout &DL,

